{
 "level": "A2–B1",
 "intro": "In this topic you will learn <strong>the passive voice in all the main tenses</strong> of English: Present, Past, and Future in the Simple, Continuous, and Perfect forms.",
 "rules": [
 {
 "label": "Principle",
 "color": "emerald",
 "text": "The basic passive formula: <strong>be (in the required tense) + V3</strong>",
 "example": "The letter is written. / was written. / will be written."
 },
 {
 "label": "Continuous",
 "color": "blue",
 "text": "For continuous tenses, we add <strong>being</strong>:",
 "example": "The house is being painted. / was being painted."
 },
 {
 "label": "Perfect",
 "color": "rose",
 "text": "For perfect tenses, we use <strong>have/had + been</strong>:",
 "example": "The work has been done. / had been done."
 }
 ]
}

{
 "title": "1. Present Tenses",
 "sections": [
 {
 "label": "Present Simple",
 "color": "emerald",
 "description": "<strong>am/is/are + V3</strong> — regular actions, facts",
 "examples": [
 {
 "en": "English is spoken in many countries.",
 "ua": "English is spoken in many countries."
 },
 {
 "en": "The rooms are cleaned every day.",
 "ua": "The rooms are cleaned every day."
 }
 ]
 },
 {
 "label": "Present Continuous",
 "color": "blue",
 "description": "<strong>am/is/are + being + V3</strong> — actions happening now",
 "examples": [
 {
 "en": "The house is being painted now.",
 "ua": "The house is being painted now."
 },
 {
 "en": "The documents are being prepared.",
 "ua": "The documents are being prepared."
 }
 ]
 },
 {
 "label": "Present Perfect",
 "color": "rose",
 "description": "<strong>has/have + been + V3</strong> — result",
 "examples": [
 {
 "en": "The project has been completed.",
 "ua": "The project has been completed."
 },
 {
 "en": "All tickets have been sold.",
 "ua": "All tickets have been sold."
 }
 ]
 }
 ]
}

{
 "title": "2. Past Tenses",
 "sections": [
 {
 "label": "Past Simple",
 "color": "emerald",
 "description": "<strong>was/were + V3</strong> — actions in the past",
 "examples": [
 {
 "en": "The house was built in 1990.",
 "ua": "The house was built in 1990."
 },
 {
 "en": "The letters were sent yesterday.",
 "ua": "The letters were sent yesterday."
 }
 ]
 },
 {
 "label": "Past Continuous",
 "color": "blue",
 "description": "<strong>was/were + being + V3</strong> — an action in progress in the past",
 "examples": [
 {
 "en": "The car was being repaired when I arrived.",
 "ua": "The car was being repaired when I arrived."
 },
 {
 "en": "The rooms were being cleaned all morning.",
 "ua": "The rooms were being cleaned all morning."
 }
 ]
 },
 {
 "label": "Past Perfect",
 "color": "rose",
 "description": "<strong>had + been + V3</strong> — an action before another past action",
 "examples": [
 {
 "en": "The work had been finished before the deadline.",
 "ua": "The work had been finished before the deadline."
 },
 {
 "en": "The tickets had been sold out before we arrived.",
 "ua": "The tickets had been sold out before we arrived."
 }
 ]
 }
 ]
}

{
 "title": "3. Future Tenses",
 "sections": [
 {
 "label": "Future Simple",
 "color": "emerald",
 "description": "<strong>will be + V3</strong> — actions in the future",
 "examples": [
 {
 "en": "The results will be announced tomorrow.",
 "ua": "The results will be announced tomorrow."
 },
 {
 "en": "You will be contacted soon.",
 "ua": "You will be contacted soon."
 }
 ]
 },
 {
 "label": "Future Continuous",
 "color": "blue",
 "description": "<strong>will be + being + V3</strong> — used very rarely",
 "examples": {
 "en": "The house will be being painted tomorrow.",
 "ua": "The house will be being painted tomorrow."
 }
 },
 {
 "label": "Future Perfect",
 "color": "rose",
 "description": "<strong>will have + been + V3</strong> — will be completed by...",
 "examples": [
 {
 "en": "The work will have been completed by Friday.",
 "ua": "The work will have been completed by Friday."
 },
 {
 "en": "All emails will have been sent by 6 PM.",
 "ua": "All emails will have been sent by 6 PM."
 }
 ]
 }
 ]
}

{
 "title": "4. Summary table of all tenses",
 "intro": "Passive voice formulas in all tenses:",
 "rows": [
 {
 "en": "Present Simple",
 "ua": "Present Simple",
 "note": "The letter is written."
 },
 {
 "en": "Present Continuous",
 "ua": "Present Continuous",
 "note": "The letter is being written."
 },
 {
 "en": "Present Perfect",
 "ua": "Present Perfect",
 "note": "The letter has been written."
 },
 {
 "en": "Past Simple",
 "ua": "Past Simple",
 "note": "The letter was written."
 },
 {
 "en": "Past Continuous",
 "ua": "Past Continuous",
 "note": "The letter was being written."
 },
 {
 "en": "Past Perfect",
 "ua": "Past Perfect",
 "note": "The letter had been written."
 },
 {
 "en": "Future Simple",
 "ua": "Future Simple",
 "note": "The letter will be written."
 },
 {
 "en": "Future Perfect",
 "ua": "Future Perfect",
 "note": "The letter will have been written."
 }
 ],
 "warning": "📌 Future Continuous Passive (will be being + V3) is used very rarely!"
}
